    const n = nums.length;

    // 1. Find the peak index
    let peakIndex = 0;
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            peakIndex = i;
        } else {
            // Once it starts decreasing or stays the same (though strictly decreasing is expected after peak), 
            // we've found the peak index (or passed it if the peak was at i-1)
            // Since it's guaranteed to be unimodal, we can stop searching for the strictly increasing part's end.
