    // A more robust way to find the peak index for a guaranteed unimodal array:
    let maxVal = -Infinity;
    let maxIdx = -1;
    for (let i = 0; i < n; i++) {
        if (nums[i] > maxVal) {
            maxVal = nums[i];
            maxIdx = i;
        }
    }
    const peak = maxIdx;

    // 2. Calculate the sum of the increasing part (from 0 to peak, inclusive)
    let sumIncreasing = 0;
    for (let i = 0; i <= peak; i++) {
        sumIncreasing += nums[i];
    }

    // 3. Calculate the sum of the decreasing part (from peak to n-1, inclusive)
    let sumDecreasing = 0;
    for (let i = peak; i < n; i++) {
        sumDecreasing += nums[i];
    }

    // 4. Compare the sums
    if (sumIncreasing > sumDecreasing) {
        return 0;
    } else if (sumDecreasing > sumIncreasing) {
        return 1;
    } else {
        return -1;
    }
}

